// Quiz Questions organized by Class/Grade Level with Sets
// Below 3rd: 5 questions per set | Others: 10 questions per set

export interface Question {
    question: string;
    options: string[];
    correct: number;
    category: string;
}

export interface QuestionSet {
    setNumber: number;
    questions: Question[];
}

export interface ClassLevel {
    id: number;
    name: string;
    subtitle: string;
    icon: string;
    color: string;
    questionCount: number;
    questionsPerSet: number;
    timePerQuestion: number;
    sets: QuestionSet[];
}

// Helper to divide questions into sets
function createSets(questions: Question[], questionsPerSet: number): QuestionSet[] {
    const sets: QuestionSet[] = [];
    for (let i = 0; i < questions.length; i += questionsPerSet) {
        sets.push({
            setNumber: Math.floor(i / questionsPerSet) + 1,
            questions: questions.slice(i, i + questionsPerSet),
        });
    }
    return sets;
}

